import re
import nltk
from string import punctuation
import pandas as pd

def task_func(df):
    # Check if DataFrame is empty
    if df.empty:
        raise ValueError("DataFrame is empty")

    # Check if necessary columns exist
    if 'Title' not in df.columns or 'Content' not in df.columns:
        raise ValueError("DataFrame must contain 'Title' and 'Content' columns")

    # Initialize list to store matching articles
    matching_articles = []

    # Find articles with titles containing "like" or "what" (case-insensitive)
    for index, row in df.iterrows():
        title = str(row['Title']).lower()
        if 'like' in title or 'what' in title:
            matching_articles.append(str(row['Content']))

    # If no matching articles found, return empty dict
    if not matching_articles:
        return {}

    # Combine all content into one string
    all_content = ' '.join(matching_articles)

    # Tokenize using NLTK
    tokens = nltk.word_tokenize(all_content)

    # Remove punctuation and convert to lowercase
    words = [word.lower() for word in tokens if word not in punctuation]

    # Count frequency of each word
    word_freq = {}
    for word in words:
        if word in word_freq:
            word_freq[word] += 1
        else:
            word_freq[word] = 1

    return word_freq

# Test with example
if __name__ == "__main__":
    data = {'Title': ['What is happening', 'Nothing special'], 'Content': ['Like what you see?', 'Just normal text.']}
    df = pd.DataFrame(data)
    result = task_func(df)
    print(result)

