import json
import re
import pandas as pd

def task_func(json_str):
    if not json_str:
        return pd.DataFrame()

    try:
        data = json.loads(json_str)
    except json.JSONDecodeError:
        return pd.DataFrame()

    if not isinstance(data, dict):
        return pd.DataFrame()

    # Normalize the dictionary by doubling numerical values
    normalized_data = {}

    for key, value in data.items():
        if isinstance(value, (int, float)):
            normalized_data[key] = value * 2
        elif isinstance(value, list):
            normalized_list = []
            for item in value:
                if isinstance(item, (int, float)):
                    normalized_list.append(item * 2)
                elif isinstance(item, str):
                    # Try to convert string to number
                    num_match = re.search(r'^-?\d+\.?\d*$', item)
                    if num_match:
                        normalized_list.append(float(item) * 2)
                    else:
                        normalized_list.append(item)
                else:
                    normalized_list.append(item)
            normalized_data[key] = normalized_list
        elif isinstance(value, str):
            # Try to convert string to number
            num_match = re.search(r'^-?\d+\.?\d*$', value)
            if num_match:
                normalized_data[key] = float(value) * 2
            else:
                normalized_data[key] = value
        else:
            normalized_data[key] = value

    # Create DataFrame
    try:
        df = pd.DataFrame([normalized_data])
        # Convert all numerical columns to float
        for col in df.columns:
            if df[col].dtype == 'object':
                # Check if all values in column are numeric
                try:
                    df[col] = pd.to_numeric(df[col], errors='ignore')
                except:
                    pass
        return df
    except:
        return pd.DataFrame()

# Test with the example
json_str = '{"a": [1, 2, 3], "b": 4.9, "c": "5"}'
