import pandas as pd
import numpy as np
import itertools

def task_func(data_list=[('a', 1, 2.1), ('b', 2, 3.2), ('c', 3, 4.3), ('d', 4, 5.4), ('e', 5, 6.5)]):
    if not data_list:
        return pd.DataFrame(columns=['Mean Value'])

    # Transpose the data to get columns by position
    transposed = list(itertools.zip_longest(*data_list, fillvalue=np.nan))

    means = []
    for col in transposed:
        # Filter out non-numeric values
        numeric_values = [x for x in col if isinstance(x, (int, float)) and not np.isnan(x)]
        if numeric_values:
            means.append(np.mean(numeric_values))
        else:
            means.append(np.nan)

    # Create DataFrame with appropriate index
    index = [f'Position {i}' for i in range(len(means))]
    return pd.DataFrame({'Mean Value': means}, index=index)

