import os
import re
from pathlib import Path


def task_func(dir_path: str, predicates: list) -> dict:
    # Validate directory
    if not os.path.exists(dir_path):
        raise FileNotFoundError("Directory does not exist")

    if not os.path.isdir(dir_path):
        raise FileNotFoundError("Path is not a directory")

    # Define valid predicates
    valid_predicates = {'is_file', 'is_dir', 'has_special_chars', 'has_numbers'}

    # Deduplicate predicates while preserving order
    seen = set()
    unique_predicates = []
    for pred in predicates:
        if pred in valid_predicates and pred not in seen:
            unique_predicates.append(pred)
            seen.add(pred)

    # Raise error if no valid predicates
    if not unique_predicates:
        raise ValueError("No valid predicates provided")

    # Initialize result dictionary
    result = {}

    # Iterate through directory items
    try:
        for item in os.listdir(dir_path):
            item_path = os.path.join(dir_path, item)

            # Get just the filename (no path)
            item_name = os.path.basename(item_path)

            # Initialize result for this item
            item_result = {}

            # Check each predicate
            for predicate in unique_predicates:
                if predicate == 'is_file':
                    item_result[predicate] = os.path.isfile(item_path)
                elif predicate == 'is_dir':
                    item_result[predicate] = os.path.isdir(item_path)
                elif predicate == 'has_special_chars':
                    # Remove extension for checking
                    name_without_ext = item_name
                    if '.' in item_name:
                        name_without_ext = '.'.join(item_name.split('.')[:-1])

                    # Check if any character is not letter, digit, or underscore
                    item_result[predicate] = bool(re.search(r'[^a-zA-Z0-9_]', name_without_ext))
                elif predicate == 'has_numbers':
                    # Check if name contains any digit
                    item_result[predicate] = bool(re.search(r'\d', item_name))

            result[item_name] = item_result

    except Exception as e:
        raise e

    return result

