import codecs
import pytesseract

IMAGE_PATH = "image.png"

def task_func(filename=IMAGE_PATH, from_encoding="cp1251", to_encoding="utf8"):
    try:
        # Try OCR first
        img = Image.open(filename)
        text = pytesseract.image_to_string(img)

        # If OCR successful, convert encoding
        if text.strip():
            try:
                # Decode from source encoding and encode to target encoding
                decoded_text = text.encode(from_encoding).decode(from_encoding)
                converted_text = decoded_text.encode(from_encoding).decode(to_encoding)
                return converted_text
            except (UnicodeDecodeError, LookupError):
                raise ValueError("Invalid encoding specified")

        # If OCR fails, try to get image comment
        else:
            try:
                # Try to get image comment
                comment = img.info.get("comment", "")
                if comment:
                    # Convert comment encoding
                    if isinstance(comment, bytes):
                        comment = comment.decode(from_encoding)
                    return comment.encode(from_encoding).decode(to_encoding)
                else:
                    return ""
            except (UnicodeDecodeError, LookupError):
                raise ValueError("Invalid encoding specified")

    except Exception:
        # If both OCR and comment processing fail, return empty string
        return ""

